const LANG_NAMES = { pt: "Português", en: "English", fr: "Français", es: "Español" };
const SUPPORTED_LANGS = ["pt", "en", "fr", "es"];

/* idioma atual (memória + deteção do browser) */
function getInitialLang() {
  try {
    const saved = localStorage.getItem('exodo-lang');
    if (saved && SUPPORTED_LANGS.includes(saved)) return saved;
  } catch (e) {}
  const nav = (navigator.language || 'pt').slice(0, 2).toLowerCase();
  return SUPPORTED_LANGS.includes(nav) ? nav : 'pt';
}
let CURRENT_LANG = getInitialLang();

/* t('chave') devolve a string traduzida no idioma atual */
function t(key, vars) {
  let s = (I18N[CURRENT_LANG] && I18N[CURRENT_LANG][key]) || (I18N.pt[key]) || key;
  if (vars) for (const k in vars) s = s.replace('{' + k + '}', vars[k]);
  return s;
}
